14	//
15	// Author: Brad Hyslop <bhyslop@scaleinvariant.org>
16	//
17	// RBTDRD — dogfight cloud-build viability fixture
18	//
19	// Proves the cloud-depot build-and-retrieve path yields a *runnable*
20	// artifact, with no crucible apparatus. Standing-depot scenario fixture,
21	// sibling to canonical-invest in the operator-precondition family: it reuses
22	// a depot the operator has levied by hand (no levy, no unmake) and assumes a
23	// director + retriever already invested. It differs from the skirmish chain
24	// on the crucible axis — dogfight charges NO crucible. It proves only
25	// build → summon → run viability, not containment (the crucible's orthogonal
26	// concern).
27	//
28	// Single case, ordain → summon → run → abjure, threaded through one body. The
29	// busybox vessel is consumerless — no nameplate holds its hallmark, so there
30	// is no committed regime file to carry the ephemeral hallmark across a
31	// case boundary. The hallmark therefore lives as a local across the steps,
32	// the same structural choice rbtdrc_hallmark_lifecycle makes for the same
33	// reason. This fixture IS hallmark_lifecycle with the registry-inventory
34	// middle (audit/rekon) swapped for summon + a bare container-runtime run.
35	
36	use std::path::{Path, PathBuf};
37	use std::process::Command;
38	
39	use crate::case;
40	use crate::rbtdrb_probe::{rbtdrb_assert, rbtdrb_Probe};
41	use crate::rbtdrc_crucible::{
42	    rbtdrc_docker_inspect, rbtdrc_with_ctx, RBTDRC_ARK_BASENAME_IMAGE, RBTDRC_BUSYBOX_VESSEL_DIR,
43	    RBTDRC_FACT_ARK_STEM, RBTDRC_FACT_GAR_ROOT, RBTDRC_FACT_HALLMARK,
44	};
45	use crate::rbtdre_engine::{rbtdre_Case, rbtdre_Disposition, rbtdre_Fixture, rbtdre_Verdict};
46	use crate::rbtdri_invocation::{
47	    rbtdri_invoke_global, rbtdri_read_burv_fact, rbtdri_Context, RBTDRI_BURE_CONFIRM_KEY,
48	    RBTDRI_BURE_CONFIRM_SKIP,
49	};
50	use crate::rbtdrk_canonical::rbtdrk_canonical_rbra;
51	use crate::rbtdgc_consts::{RBTDGC_ABJURE_HALLMARK, RBTDGC_ORDAIN_HALLMARK, RBTDGC_SUMMON_HALLMARK};
52	use crate::rbtdrm_manifest::RBTDRM_ROLE_DIRECTOR;
53	
54	/// Container runtime for the bare executability proof. Hardcoded to docker;
55	/// podman is deferred to the Director-governed runtime-regime decision that
56	/// rides with ₣BS. This single named site is the future swap point — do NOT
57	/// add a regime field here now.
58	const RBTDRD_RUNTIME: &str = "docker";
59	
60	/// Degenerate command proving the summoned image is runnable. busybox's
61	/// default cmd is `sh`; passing an explicit `true` yields a clean exit-0
62	/// executability proof without spawning an interactive shell.
63	const RBTDRD_PROOF_CMD: &str = "true";
64	
65	// ── Probe ────────────────────────────────────────────────────
66	//
67	// Probes are pure `fn() -> Result<(), String>` per the rbtdrb_Probe shape and
68	// have no context, so they read the project root from current_dir() — theurge
69	// always launches from the project root.
70	
71	fn rbtdrd_probe_root() -> Result<PathBuf, String> {
72	    std::env::current_dir().map_err(|e| format!("cannot resolve project root: {}", e))
73	}
74	
75	/// Precondition: director RBRA present at the canonical secrets path —
76	/// evidence an operator has levied the standing depot and invested a director
77	/// (the role that ordains and abjures). Mirrors onboarding's governor-RBRA
78	/// probe shape. The retriever credential summon needs is not separately
79	/// probed; summon fails loud if it is absent.
80	fn rbtdrd_probe_director_rbra() -> Result<(), String> {
81	    let root = rbtdrd_probe_root()?;
82	    let path = rbtdrk_canonical_rbra(&root, RBTDRM_ROLE_DIRECTOR)?;
83	    if !path.exists() {
84	        return Err(format!("director RBRA absent at {}", path.display()));
85	    }
86	    Ok(())
87	}
88	
89	// ── Runtime run helper ───────────────────────────────────────
90	
91	/// Run `<runtime> run --rm <image_ref> <cmd>` and return Ok on exit 0. The
92	/// single site naming the container runtime — see RBTDRD_RUNTIME.
93	fn rbtdrd_runtime_run(image_ref: &str, cmd: &str, dir: &Path) -> Result<(), String> {
94	    let output = Command::new(RBTDRD_RUNTIME)
95	        .args(["run", "--rm", image_ref, cmd])
96	        .output()
97	        .map_err(|e| format!("{} run exec failed: {}", RBTDRD_RUNTIME, e))?;
98	    let _ = std::fs::write(dir.join("run-stdout.txt"), &output.stdout);
99	    let _ = std::fs::write(dir.join("run-stderr.txt"), &output.stderr);
100	    if !output.status.success() {
101	        return Err(format!(
102	            "{} run --rm {} {} exited {}: {}",
103	            RBTDRD_RUNTIME,
104	            image_ref,
105	            cmd,
106	            output.status.code().unwrap_or(-1),
107	            String::from_utf8_lossy(&output.stderr).trim()
108	        ));
109	    }
110	    Ok(())
111	}
112	
113	// ── Case ─────────────────────────────────────────────────────
114	
115	fn rbtdrd_build_run_lifecycle(dir: &Path) -> rbtdre_Verdict {
116	    let probe = rbtdrb_Probe {
117	        name: "director RBRA present",
118	        check: rbtdrd_probe_director_rbra,
119	        remediation:
120	            "levy a standing depot and invest a director (canonical-invest or rbw-adI) before this fixture",
121	    };
122	    if let Err(v) = rbtdrb_assert(&probe) {
123	        return v;
124	    }
125	    rbtdrc_with_ctx(|ctx| rbtdrd_build_run_lifecycle_impl(ctx, dir))
126	}
127	
128	fn rbtdrd_build_run_lifecycle_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
129	    let vessel_dir = RBTDRC_BUSYBOX_VESSEL_DIR;
130	    if !ctx.project_root().join(vessel_dir).is_dir() {
131	        return rbtdre_Verdict::Fail(format!("vessel directory not found: {}", vessel_dir));
132	    }
133	
134	    // Ordain (conjure-mode): build busybox into the standing depot, capturing
135	    // the hallmark plus the gar_root/ark_stem facts needed to name the
136	    // locally-pulled image after summon.
137	    let _ = std::fs::write(dir.join("01-ordain.txt"), "ordaining busybox");
138	    let ordain = match rbtdri_invoke_global(ctx, RBTDGC_ORDAIN_HALLMARK, &[vessel_dir], &[]) {
139	        Ok(r) if r.exit_code == 0 => r,
140	        Ok(r) => {
141	            return rbtdre_Verdict::Fail(format!("ordain failed (exit {})\n{}", r.exit_code, r.stderr))
142	        }
143	        Err(e) => return rbtdre_Verdict::Fail(format!("ordain invocation: {}", e)),
144	    };
145	    let _ = std::fs::write(dir.join("01-ordain-stdout.txt"), &ordain.stdout);
146	    let hallmark = match rbtdri_read_burv_fact(&ordain, RBTDRC_FACT_HALLMARK) {
147	        Ok(v) => v,
148	        Err(e) => return rbtdre_Verdict::Fail(format!("read hallmark fact: {}", e)),
149	    };
150	    let gar_root = match rbtdri_read_burv_fact(&ordain, RBTDRC_FACT_GAR_ROOT) {
151	        Ok(v) => v,
152	        Err(e) => return rbtdre_Verdict::Fail(format!("read gar_root fact: {}", e)),
153	    };
154	    let ark_stem = match rbtdri_read_burv_fact(&ordain, RBTDRC_FACT_ARK_STEM) {
155	        Ok(v) => v,
156	        Err(e) => return rbtdre_Verdict::Fail(format!("read ark_stem fact: {}", e)),
157	    };
158	    let _ = std::fs::write(dir.join("02-hallmark.txt"), &hallmark);
159	
160	    // The image ref summon pulls locally: <gar_root>/<ark_stem>/image:<hallmark>.
161	    // Same construction onboarding's conjure verification tail uses.
162	    let image_ref = format!(
163	        "{}/{}/{}:{}",
164	        gar_root, ark_stem, RBTDRC_ARK_BASENAME_IMAGE, hallmark
165	    );
166	    let _ = std::fs::write(dir.join("02-image-ref.txt"), &image_ref);
167	
168	    // Summon: retriever pulls the hallmark's arks locally. Confirm the image
169	    // ark is resolvable before attempting to run it.
170	    let _ = std::fs::write(dir.join("03-summon.txt"), "summoning");
171	    let summon = match rbtdri_invoke_global(ctx, RBTDGC_SUMMON_HALLMARK, &[&hallmark], &[]) {
172	        Ok(r) if r.exit_code == 0 => r,
173	        Ok(r) => {
174	            return rbtdre_Verdict::Fail(format!("summon failed (exit {})\n{}", r.exit_code, r.stderr))
175	        }
176	        Err(e) => return rbtdre_Verdict::Fail(format!("summon invocation: {}", e)),
177	    };
178	    let _ = std::fs::write(dir.join("03-summon-stdout.txt"), &summon.stdout);
179	    if !rbtdrc_docker_inspect(&image_ref) {
180	        return rbtdre_Verdict::Fail(format!(
181	            "summon: image ark not local after pull: {}",
182	            image_ref
183	        ));
184	    }
185	
186	    // Bare run — the executability proof. No crucible: a plain
187	    // `<runtime> run --rm <ref> true` exiting 0 proves the summoned artifact
188	    // is runnable.
189	    let _ = std::fs::write(dir.join("04-run.txt"), "running degenerate command");
190	    if let Err(e) = rbtdrd_runtime_run(&image_ref, RBTDRD_PROOF_CMD, dir) {
191	        return rbtdre_Verdict::Fail(format!("bare run executability proof: {}", e));
192	    }
193	
194	    // Abjure — remove the hallmark's arks, restoring the standing depot to its
195	    // pre-run inventory. BURE_CONFIRM skipped for non-interactive teardown.
196	    let _ = std::fs::write(dir.join("05-abjure.txt"), "abjuring");
197	    match rbtdri_invoke_global(
198	        ctx,
199	        RBTDGC_ABJURE_HALLMARK,
200	        &[&hallmark],
201	        &[(RBTDRI_BURE_CONFIRM_KEY, RBTDRI_BURE_CONFIRM_SKIP)],
202	    ) {
203	        Ok(r) if r.exit_code == 0 => {}
204	        Ok(r) => {
205	            return rbtdre_Verdict::Fail(format!("abjure failed (exit {})\n{}", r.exit_code, r.stderr))
206	        }
207	        Err(e) => return rbtdre_Verdict::Fail(format!("abjure invocation: {}", e)),
208	    }
209	
210	    let _ = std::fs::write(dir.join("06-passed.txt"), "passed");
211	    rbtdre_Verdict::Pass
212	}
213	
214	// ── Section registry ─────────────────────────────────────────
215	
216	pub static RBTDRD_CASES_DOGFIGHT: &[rbtdre_Case] = &[case!(rbtdrd_build_run_lifecycle)];
217	
218	pub static RBTDRD_FIXTURE_DOGFIGHT: rbtdre_Fixture = rbtdre_Fixture {
219	    name: crate::rbtdrm_manifest::RBTDRM_FIXTURE_DOGFIGHT,
220	    disposition: rbtdre_Disposition::Independent,
221	    setup: None,
222	    teardown: None,
223	    cases: RBTDRD_CASES_DOGFIGHT,
224	};
